import{_ as e,c as t,o as i,a5 as a}from"./chunks/framework.D_5JO0pl.js";const n="/blog/assets/banner.i6VoMJvg.jpg",s="/blog/assets/ChunkDelete.DL8u6UXr.png",o="/blog/assets/InsertTruncate.srJPxGBY.png",r="/blog/assets/PartitionPurge.BCS-HrFM.png",b=JSON.parse('{"title":"Automating MySQL Data Purging Our Journey to Efficient Data Management","description":"Discover the ultimate guide to efficient data purging techniques for large-scale MySQL databases. Learn why we transitioned from manual purging to automated partitioning, compare different methods (Insert & Truncate, Chunk Delete, Partitioning) in detail, and understand the challenges and solutions we implemented. Our detailed analysis includes speed, data consistency, replication lag, scalability, and query performance. Perfect for database administrators and developers looking to optimize their MySQL data management and improve system performance.","frontmatter":{"title":"Automating MySQL Data Purging Our Journey to Efficient Data Management","description":"Discover the ultimate guide to efficient data purging techniques for large-scale MySQL databases. Learn why we transitioned from manual purging to automated partitioning, compare different methods (Insert & Truncate, Chunk Delete, Partitioning) in detail, and understand the challenges and solutions we implemented. Our detailed analysis includes speed, data consistency, replication lag, scalability, and query performance. Perfect for database administrators and developers looking to optimize their MySQL data management and improve system performance.","keywords":"Data purging, MySQL optimization, database partitioning, Insert & Truncate, Chunk Delete, replication lag reduction, data consistency, database scalability, query performance improvement, automated data management"},"headers":[],"relativePath":"archives/database/purging_mysql_tables_on_scale.md","filePath":"archives/database/purging_mysql_tables_on_scale.md"}'),l={name:"archives/database/purging_mysql_tables_on_scale.md"},d=a('<h1 id="automating-mysql-data-purging-our-journey-to-efficient-data-management" tabindex="-1">Automating MySQL Data Purging: Our Journey to Efficient Data Management <a class="header-anchor" href="#automating-mysql-data-purging-our-journey-to-efficient-data-management" aria-label="Permalink to &quot;Automating MySQL Data Purging: Our Journey to Efficient Data Management&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">QUOTE</p><p>Simple-sounding problems can become a real pain when scaled; what works for ten users can break down spectacularly with a million.</p><p>~ Anonymous</p></div><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p><img src="'+n+'" alt="Banner Image Placeholder"></p><p>In today&#39;s data-driven world, managing large volumes of data efficiently is paramount for maintaining optimal database performance. Being the largest consumer of MySQL within the company, we faced significant challenges with data management as our operations scaled up. Manual data purging, which was initially manageable, became increasingly labor-intensive and error-prone as data volumes grew. This blog post outlines our journey towards automating MySQL data purging, the challenges we faced, and the solutions we implemented to enhance efficiency and reliability.</p><h2 id="why-purging" tabindex="-1">Why Purging? <a class="header-anchor" href="#why-purging" aria-label="Permalink to &quot;Why Purging?&quot;">​</a></h2><p>Data purging became essential for us for several reasons:</p><ul><li><strong>Increased Disk Usage and Costs:</strong> Unchecked data growth leads to increased disk usage and associated costs. Disk usage costs nearly doubled in just 6 months.</li><li><strong>Pain of Manual Purge:</strong> Manual purging processes were time-consuming and error-prone, leading to incidents that impacted system reliability.</li><li><strong>Increasing Scale and Data Throughput:</strong> As our operations scaled, the volume of data increased exponentially, necessitating more frequent and efficient data purging strategies. We were having a monthly data throughput of 6+ TBs of data and it was growing at uncontrollable pace.</li><li><strong>Performance Costs:</strong> Large volumes of unused data can degrade database performance, affecting query response times and overall system efficiency.</li></ul><p>At end, we don&#39;t need to store data indefinitely subject to regulatory reasons, as those data were essentially logs and metadata, so purging is viable approach in our case.</p><h2 id="approaches-to-data-purging" tabindex="-1">Approaches to Data Purging <a class="header-anchor" href="#approaches-to-data-purging" aria-label="Permalink to &quot;Approaches to Data Purging&quot;">​</a></h2><p>We explored three primary approaches to automate data purging in our MySQL clusters:</p><h3 id="_1-chunk-delete" tabindex="-1">1. Chunk Delete <a class="header-anchor" href="#_1-chunk-delete" aria-label="Permalink to &quot;1. Chunk Delete&quot;">​</a></h3><p><img src="'+s+`" alt="Chunk Delete"> Chunk deletion involves breaking down the delete operation into smaller, manageable chunks instead of attempting to delete large volumes of data in a single transaction. This minimizes locking and reduces the risk of replication lag.</p><h5 id="workflow" tabindex="-1"><strong>Workflow:</strong> <a class="header-anchor" href="#workflow" aria-label="Permalink to &quot;**Workflow:**&quot;">​</a></h5><ol><li>Identify the rows to be deleted based on a specified condition (e.g., rows older than a certain date).</li><li>Split the deletion operation into chunks, each deleting a fixed number of rows.</li><li>Execute the delete operation for each chunk sequentially, depending on the system&#39;s capabilities.</li><li>Repeat until all identified rows are deleted.</li></ol><h5 id="advantages" tabindex="-1"><strong>Advantages:</strong> <a class="header-anchor" href="#advantages" aria-label="Permalink to &quot;**Advantages:**&quot;">​</a></h5><ul><li><strong>Reduced Locking:</strong> Smaller transactions reduce the duration for which the table is locked, minimizing impact on concurrent operations.</li><li><strong>Manageable Load:</strong> Distributes the load evenly over time, preventing sudden spikes in database activity.</li><li><strong>Adaptable:</strong> This method allows for flexible deletion criteria, making it possible to adjust the criteria on which data has to be deleted, as requirements change.</li></ul><h5 id="disadvantages" tabindex="-1"><strong>Disadvantages:</strong> <a class="header-anchor" href="#disadvantages" aria-label="Permalink to &quot;**Disadvantages:**&quot;">​</a></h5><ul><li><strong>Slow for Large Volumes:</strong> Deleting data in chunks can be time-consuming, especially for very large datasets.</li><li><strong>Complex Implementation:</strong> Requires careful management to ensure consistency and completeness of deletions.</li><li><strong>Possible Risk of Table Locks:</strong> There is high risk of table level lock, when doing chunk delete in parallel.</li></ul><h5 id="implementation-pseudocode" tabindex="-1"><strong>Implementation(Pseudocode):</strong> <a class="header-anchor" href="#implementation-pseudocode" aria-label="Permalink to &quot;**Implementation(Pseudocode):**&quot;">​</a></h5><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> @row_count </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">REPEAT</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  DELETE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> your_table</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  WHERE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">condition</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  LIMIT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  SET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> @row_count </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ROW_COUNT();</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">UNTIL @row_count </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">END</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> REPEAT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>This script repeats the delete operation in chunks of 1000 rows until no more rows match the condition.</p><h3 id="_2-insert-truncate" tabindex="-1">2. INSERT &amp; TRUNCATE <a class="header-anchor" href="#_2-insert-truncate" aria-label="Permalink to &quot;2. INSERT &amp; TRUNCATE&quot;">​</a></h3><p><img src="`+o+`" alt="Insert &amp; Truncate"></p><p>This approach involves copying the required data to a new table and then truncating the original table to remove unwanted data. This method is useful for scenarios where a significant portion of the table needs to be purged.</p><h5 id="workflow-1" tabindex="-1"><strong>Workflow:</strong> <a class="header-anchor" href="#workflow-1" aria-label="Permalink to &quot;**Workflow:**&quot;">​</a></h5><ol><li>Create a new table with the same schema as the original table.</li><li>Insert the data to be retained into the new table in small chunks.</li><li>Truncate the original table to delete all rows.</li><li>Re-insert the retained data back into the original table from the new table.</li><li>Drop the temporary table used for the operation.</li></ol><h5 id="advantages-1" tabindex="-1"><strong>Advantages:</strong> <a class="header-anchor" href="#advantages-1" aria-label="Permalink to &quot;**Advantages:**&quot;">​</a></h5><ul><li><strong>Efficiency for Large Purges:</strong> Effective when a large percentage of the table needs to be purged.</li><li><strong>Simpler Logic:</strong> Straightforward to implement as it primarily involves data copying and truncation.</li></ul><h5 id="disadvantages-1" tabindex="-1"><strong>Disadvantages:</strong> <a class="header-anchor" href="#disadvantages-1" aria-label="Permalink to &quot;**Disadvantages:**&quot;">​</a></h5><ul><li><strong>Non-Atomic Operation:</strong> The process involves multiple steps, which are not atomic, leading to potential data inconsistency if interrupted.</li><li><strong>Temporary Disk Usage:</strong> Requires additional disk space for the temporary table holding the retained data.</li><li><strong>Lossy:</strong> This approach in non-locked situation will inherently ignore any UPDATE/DELETE done in between copy op, losing on data integrity.</li><li><strong>Replication Lag:</strong> During manual purges we observed replication lag of more than 20~30 minutes between master and slave nodes, during purge, significantly affecting data consistency.</li></ul><h5 id="implementation-pseudocode-1" tabindex="-1"><strong>Implementation(Pseudocode):</strong> <a class="header-anchor" href="#implementation-pseudocode-1" aria-label="Permalink to &quot;**Implementation(Pseudocode):**&quot;">​</a></h5><div class="warning custom-block"><p class="custom-block-title">INFO</p><p>Ignoring the edge cases when data was inserted between copy for brevity!</p></div><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CREATE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> TABLE</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> new_table</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> LIKE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> your_table;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">--- Copy in small chunks if data volume is high</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">INSERT INTO</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> new_table </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> your_table </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">condition</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">TRUNCATE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> TABLE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> your_table;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">INSERT INTO</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> your_table </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> new_table;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DROP</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> TABLE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> new_table;</span></span></code></pre></div><p>This script transfers data, truncates the original table, and then reinserts the retained data.</p><h4 id="_3-partitioning" tabindex="-1">3. Partitioning <a class="header-anchor" href="#_3-partitioning" aria-label="Permalink to &quot;3. Partitioning&quot;">​</a></h4><p><img src="`+r+`" alt="Partitioning Approach"></p><p>Partitioning involves dividing a table into smaller, more manageable partitions based on a specified column, such as an ID or a DateTime column. This allows for efficient purging by dropping entire partitions instead of deleting individual rows.</p><h5 id="workflow-2" tabindex="-1"><strong>Workflow:</strong> <a class="header-anchor" href="#workflow-2" aria-label="Permalink to &quot;**Workflow:**&quot;">​</a></h5><ol><li>Modify the table schema to include partitioning based on a chosen column. (Not required, if partitioning based on PRIMARY KEY)</li><li>Create partitions to divide the table data according to the partition key.</li><li>For purging, drop partitions that contain no new data far from the retention period.</li><li>Create additional empty partitions to accommodate future data.</li></ol><h5 id="advantages-2" tabindex="-1"><strong>Advantages:</strong> <a class="header-anchor" href="#advantages-2" aria-label="Permalink to &quot;**Advantages:**&quot;">​</a></h5><ul><li><strong>Efficiency:</strong> Dropping partitions is faster and more efficient than row-by-row deletion.</li><li><strong>Atomic Operation:</strong> Partition operations are atomic, ensuring data consistency &amp; integrity.</li><li><strong>Minimal Replication Lag:</strong> Significantly reduces replication lag during purging. (in order of ms)</li></ul><h5 id="disadvantages-2" tabindex="-1"><strong>Disadvantages:</strong> <a class="header-anchor" href="#disadvantages-2" aria-label="Permalink to &quot;**Disadvantages:**&quot;">​</a></h5><ul><li><strong>Schema Changes:</strong> Requires altering the table schema to introduce partitioning if using datetime column, as</li><li><strong>Complexity in Management:</strong> Needs careful management of partition keys and partition lifecycle.</li><li><strong>Potential issues with JOIN queries:</strong> While benchmarking we saw 60x slower queries performance on selected queries having JOINs, while it resolved with a simple <code>ANALYZE TABLE</code> on the partitioned table, but this needed more diagnosis.</li></ul><h5 id="implementation" tabindex="-1"><strong>Implementation:</strong> <a class="header-anchor" href="#implementation" aria-label="Permalink to &quot;**Implementation:**&quot;">​</a></h5><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ALTER</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> TABLE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> your_table</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">PARTITION</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> BY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> RANGE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">PRIMARY KEY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) (</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  PARTITION</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> p0 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">VALUES</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> LESS THAN (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  PARTITION</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> p1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">VALUES</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> LESS THAN (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ...</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- For purging (if p0 is expired)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ALTER</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> TABLE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> your_table </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DROP</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> PARTITION</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> p0;</span></span></code></pre></div><p>This script sets up partitioning based on a primary key column and drops partitions as needed.</p><h3 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Criteria</th><th>Insert &amp; Truncate</th><th>Chunk Delete</th><th>Partitioning</th></tr></thead><tbody><tr><td><strong>Speed</strong></td><td>Moderate to Slow (2-3 hrs on 1 TB table)</td><td>Slow</td><td>Blazingly Fast</td></tr><tr><td></td><td>Requires copying and renaming tables, which can be time-consuming for large datasets.</td><td>Deletes data in chunks, leading to slower overall process.</td><td>Drops entire partitions quickly, minimizing time required.</td></tr><tr><td><strong>Data Consistency</strong></td><td>Can cause issues if data is updated during the process</td><td>Ensures data consistency, but the process is slower</td><td>Ensures high consistency by dropping entire partitions atomically</td></tr><tr><td><strong>Replication Lag</strong></td><td>High replication lag</td><td>Moderate replication lag</td><td>Minimal replication lag</td></tr><tr><td></td><td>Significant lag due to large-scale data copying.</td><td>Moderate lag as it deletes data in smaller chunks.</td><td>Minimal lag since partitions are dropped swiftly.</td></tr><tr><td><strong>Implementation Complexity</strong></td><td>Moderate to High</td><td>Moderate</td><td>High</td></tr><tr><td></td><td>Needs handling of table renames and potential downtime</td><td>Requires careful management of chunk sizes and deletion intervals.</td><td>Requires schema changes, partition management, and complex setup.</td></tr><tr><td><strong>Scalability</strong></td><td>Limited</td><td>Limited to Moderate</td><td>High</td></tr><tr><td></td><td>Not suitable for very large datasets due to performance issues.</td><td>Can become inefficient with very large datasets.</td><td>Scales well with very large datasets.</td></tr><tr><td><strong>Flexibility</strong></td><td>High</td><td>High</td><td>Low to Moderate</td></tr><tr><td></td><td>Flexible deletion criteria based on TTL and other factors.</td><td>Flexible with fine-grained control over deletion.</td><td>Less flexible due to partition constraints and requirements.</td></tr><tr><td><strong>Downtime Requirement</strong></td><td>Potential for significant downtime</td><td>Minimal downtime, but longer overall process</td><td>Minimal to no downtime</td></tr><tr><td></td><td>Requires downtime for large-scale data copying.</td><td>Deletes data live on the table, requiring minimal downtime.</td><td>Partitions can be managed with minimal impact on live operations.</td></tr><tr><td><strong>Table Lock Requirement</strong></td><td>May require lock, depending on implementation</td><td>No table lock required</td><td>No table lock required</td></tr><tr><td></td><td>Lock may be required during the renaming process.</td><td>Deletes data in chunks without locking the entire table.</td><td>Drops partitions without locking the entire table.</td></tr><tr><td><strong>Query Performance</strong></td><td>No significant impact</td><td>No significant impact</td><td>Potential adverse impact, especially with joins</td></tr><tr><td><strong>Ease of Monitoring &amp; Debugging</strong></td><td>Moderate</td><td>Moderate to High</td><td>Moderate to High</td></tr><tr><td></td><td>Needs careful monitoring during copying and renaming.</td><td>Requires detailed monitoring to ensure chunk deletions are processed correctly.</td><td>Requires monitoring of partition states and potential performance impacts.</td></tr><tr><td><strong>Suitability for Large Data Sets</strong></td><td>Limited</td><td>Limited</td><td>High</td></tr><tr><td></td><td>Performance issues with very large tables.</td><td>Can be inefficient with high volumes of data.</td><td>Designed to handle large volumes of data efficiently.</td></tr></tbody></table><h3 id="why-we-preffered-partitioning" tabindex="-1">Why we preffered Partitioning? <a class="header-anchor" href="#why-we-preffered-partitioning" aria-label="Permalink to &quot;Why we preffered Partitioning?&quot;">​</a></h3><p>We prefer partitioning due to its efficiency and reliability in handling large datasets. Here’s why I believe it’s the best approach:</p><ul><li><strong>Fast and Atomic:</strong> Dropping partitions is significantly faster and ensures atomic operations, maintaining data consistency.</li><li><strong>Minimal Impact on Live Systems:</strong> It reduces replication lag and avoids locking the entire table, ensuring smooth database operations.</li><li><strong>Scalability:</strong> Partitioning efficiently manages large datasets, making it suitable for our scale of operations.</li></ul><h3 id="why-partitioning-for-archival" tabindex="-1">Why Partitioning for Archival? <a class="header-anchor" href="#why-partitioning-for-archival" aria-label="Permalink to &quot;Why Partitioning for Archival?&quot;">​</a></h3><p>While partitioning is often used for performance optimization, our primary goal was efficient archival. Dropping partitions is much faster than row-by-row deletion, making it ideal for removing large volumes of old data quickly and efficiently.</p><h3 id="migrating-non-partitioned-table-to-partition-table" tabindex="-1">Migrating Non-Partitioned Table to Partition Table <a class="header-anchor" href="#migrating-non-partitioned-table-to-partition-table" aria-label="Permalink to &quot;Migrating Non-Partitioned Table to Partition Table&quot;">​</a></h3><p>To implement partitioning, we needed to migrate our existing non-partitioned tables to partitioned tables. This process presented several challenges.</p><h4 id="pain-points-with-migration" tabindex="-1">Pain Points with Migration <a class="header-anchor" href="#pain-points-with-migration" aria-label="Permalink to &quot;Pain Points with Migration&quot;">​</a></h4><ul><li><strong>Scale:</strong> Migrating large tables to a partitioned schema presented significant challenges.</li><li><strong>Live Data:</strong> Ensuring minimal or no downtime during migration was critical to avoid impacting live operations.</li><li><strong>Schema Changes:</strong> Implementing partitioning required schema modifications, which needed to be handled carefully to avoid disruptions.</li><li><strong>Lengthy process:</strong> To account for replication lag, we intentionally have to keep this process slow for a reason, which can be a pain!</li></ul><h4 id="how-we-migrated" tabindex="-1">How We Migrated <a class="header-anchor" href="#how-we-migrated" aria-label="Permalink to &quot;How We Migrated&quot;">​</a></h4><p>To overcome these challenges, we adopted the following strategies:</p><ul><li><strong>Using ID as Partition Column:</strong> Instead of using a DateTime column, we used the ID column as the partition key. This avoided the need for extensive schema changes and leveraged the primary key for efficient partitioning.</li><li><strong>Minimal Downtime:</strong> We developed a automated pipeline to handle the migration process in stages, ensuring minimal impact on live systems.</li><li><strong>Minimal Labor:</strong> The amount of Labor with Migration was paramount, so we developed a automated pipeline to automated migration! One only need to put the config in YAML and pipeline will automatically pick it up and migrate it using &quot;INSERT &amp; TRUNCATE&quot; approach, accounting for edge cases as well. We ensured that read miss of hot data is minimal to extent that it can be safely ignored!</li></ul><h3 id="how-we-migrated-1" tabindex="-1">How We Migrated <a class="header-anchor" href="#how-we-migrated-1" aria-label="Permalink to &quot;How We Migrated&quot;">​</a></h3><p>Migrating our non-partitioned tables to partitioned tables required a carefully planned approach to minimize downtime and ensure data consistency. Here is a detailed breakdown of the process:</p><ol><li><p><strong>Choosing the Partition Column:</strong></p><ul><li>Initially, we considered using the DateTime column for partitioning. However, this required significant schema changes and was expensive to implement.</li><li>Hence, we opted to use the ID column instead. The ID column, typically the primary key, did not require extensive schema modifications and facilitated a smoother transition.</li></ul></li><li><p><strong>Creating Partitioned Tables:</strong></p><ul><li>We created new tables with partitions based on the ID column. This involved defining the partitioning scheme and ensuring that the partitioning column had unique keys.</li><li>We ensured that indexes and necessary constraints were replicated in the new partitioned tables.</li></ul></li><li><p><strong>Data Migration:</strong></p><ul><li>Data migration was done in chunks to minimize the impact on live operations. We copied data from the non-partitioned tables to the new partitioned tables in batches using &quot;INSERT &amp; TRUNCATE&quot; approach.</li><li>During this process, we maintained data consistency by ensuring that ongoing write operations to the old tables were also reflected in the new tables.</li></ul></li><li><p><strong>Validation:</strong></p><ul><li>After migrating the data, we validated the new partitioned tables to ensure data integrity and consistency.</li><li>This involved running consistency checks and comparing row counts between the old and new tables.</li></ul></li><li><p><strong>Switchover:</strong></p><ul><li>Once validation was complete, we performed the switchover. This involved renaming the old tables to a backup name and renaming the new partitioned tables to the original table names and ultimately dropping the old table.</li></ul></li><li><p><strong>Post-Migration Steps:</strong></p><ul><li>After the switchover, we monitored the performance and behavior of the new partitioned tables to ensure everything was functioning as expected.</li><li>We also set up appropriate monitoring and alerting for the new partitioned tables.</li></ul></li></ol><h3 id="the-nitpicks" tabindex="-1">The Nitpicks <a class="header-anchor" href="#the-nitpicks" aria-label="Permalink to &quot;The Nitpicks&quot;">​</a></h3><p>Despite partitioning being our primary approach, we also needed an archival purge method for edge cases. This involved using insert &amp; truncate or chunk delete depending on the volume of data to be purged. We preffered archival purge when we couldn&#39;t predict query performance on partitioned table or we couldn&#39;t bear the schemas changes on the table.</p><ol><li><p><strong>Archival Purge:</strong></p><ul><li>For smaller deletions, chunk delete was more efficient. We deleted data in small chunks iteratively to avoid locking the entire table.</li><li>For larger deletions, insert &amp; truncate was more appropriate. We copied the required data to a new table and truncated the old table. This method, while requiring significant downtime, was effective for handling large deletions.</li></ul></li><li><p><strong>Choosing the Right Approach:</strong></p><ul><li>The decision between chunk delete and insert &amp; truncate was based on the percentage of data to be deleted. If the data to be deleted was less than 20% of the total rows, chunk delete was used. For larger deletions, insert &amp; truncate was the chosen method.</li></ul></li><li><p><strong>Ensuring Data Consistency:</strong></p><ul><li>During repeated runs of the pipeline, we ensured data consistency by intelligently choosing between the different approaches based on the size of the data to be purged.</li><li>This helped in maintaining the reliability of the system and preventing any data loss.</li></ul></li></ol><h3 id="why-we-didn-t-use-tools-like-pt-archiver-and-maatkit" tabindex="-1">Why We Didn&#39;t Use Tools like pt-archiver and Maatkit <a class="header-anchor" href="#why-we-didn-t-use-tools-like-pt-archiver-and-maatkit" aria-label="Permalink to &quot;Why We Didn&#39;t Use Tools like pt-archiver and Maatkit&quot;">​</a></h3><p>While considering different approaches to automate data purging, we evaluated existing tools like <strong>pt-archiver</strong> and <strong>Maatkit</strong> (now integrated into Percona Toolkit). These tools are widely used for archiving and purging data in MySQL databases, providing granular control and monitoring capabilities. However, there were several reasons we decided not to use them:</p><ol><li><p><strong>Scalability:</strong><br> Our database handles millions of rows daily and terabytes of data. Pt-archiver and Maatkit, while effective for smaller datasets, may not scale efficiently to our needs.</p></li><li><p><strong>Complexity:</strong><br> Configuring these tools to meet our requirements involves complex setups, increasing the risk of misconfigurations and debugging challenges.</p></li><li><p><strong>Monitoring and Debugging:</strong><br> We needed more granular monitoring and easier debugging than pt-archiver and Maatkit offer. Our custom solution provides detailed logging, alerting, and metrics specific to our needs.</p></li><li><p><strong>Custom Requirements:</strong><br> Our custom solution allows flexible deletion strategies and incorporates specific business logic, which would be complex and inefficient to implement with third-party tools.</p></li></ol><h2 id="results" tabindex="-1">Results <a class="header-anchor" href="#results" aria-label="Permalink to &quot;Results&quot;">​</a></h2><p>The implementation of automated data purging yielded significant improvements:</p><ul><li><strong>60x Decrease in Replication Lag:</strong> The replication lag during purging operations was drastically reduced, ensuring smoother database operations.</li><li><strong>Terabytes of Disk Freed:</strong> Efficient purging freed up substantial disk space, optimizing storage utilization and reducing costs.</li><li><strong>Time Saved:</strong> Automated purging saves approximately 90+ hours annualy, previously spent on manual processes.</li></ul><h2 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion&quot;">​</a></h2><p>Automating MySQL data purging transformed our data management practices, enhancing efficiency, reliability, and scalability. By adopting partitioning and addressing edge cases with hybrid approaches, we achieved significant operational improvements. This journey underscores the importance of continuously evolving data management strategies to keep pace with growing data volumes and operational demands.</p><h2 id="good-reads" tabindex="-1">Good Reads <a class="header-anchor" href="#good-reads" aria-label="Permalink to &quot;Good Reads&quot;">​</a></h2><ol><li><a href="https://mysql.rjweb.org/doc.php/partitionmaint" target="_blank" rel="noreferrer">https://mysql.rjweb.org/doc.php/partitionmaint</a></li><li><a href="https://mysql.rjweb.org/doc.php/deletebig" target="_blank" rel="noreferrer">https://mysql.rjweb.org/doc.php/deletebig</a></li><li><a href="https://docs.percona.com/percona-toolkit/pt-archiver.html" target="_blank" rel="noreferrer">https://docs.percona.com/percona-toolkit/pt-archiver.html</a></li></ol>`,77),h=[d];function p(g,c,u,m,k,f){return i(),t("div",null,h)}const w=e(l,[["render",p]]);export{b as __pageData,w as default};
